import React from 'react';
import { motion } from 'framer-motion';
import './DashboardStats.css';

const DashboardStats = ({ analytics }) => {
  const stats = [
    {
      title: 'Total Predictions',
      value: analytics?.total_predictions || 0,
      icon: '📊',
      color: '#2563eb'
    },
    {
      title: 'High Risk %',
      value: `${analytics?.high_risk_percentage || 0}%`,
      icon: '⚠️',
      color: '#ef4444'
    },
    {
      title: 'Low Risk %',
      value: `${analytics?.low_risk_percentage || 0}%`,
      icon: '✅',
      color: '#22c55e'
    },
    {
      title: 'Average Risk Score',
      value: `${analytics?.average_risk_score || 0}%`,
      icon: '📈',
      color: '#7c3aed'
    }
  ];

  return (
    <div className="dashboard-stats">
      {stats.map((stat, index) => (
        <motion.div
          key={stat.title}
          className="stat-card"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: index * 0.1 }}
          whileHover={{ y: -5, transition: { duration: 0.2 } }}
        >
          <div className="stat-icon" style={{ color: stat.color }}>
            {stat.icon}
          </div>
          <div className="stat-content">
            <h3 style={{ color: stat.color }}>{stat.value}</h3>
            <p>{stat.title}</p>
          </div>
        </motion.div>
      ))}
    </div>
  );
};

export default DashboardStats;
